"use client";

import { register } from "module";
import { useRouter } from "next/navigation";
import React, { useEffect, useState } from "react";
import { Form, Button, Container, Row, Col } from "react-bootstrap";

export default function Register() {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: "",
    email: "",
    phone_number: "",
    country_id: "",
    id_proof: "",
    password: "",
    confirmPassword: "",
    program_id: "",
    university_id: "",
    tenth_certificate: null,
    twelfth_certificate: null,
    other_certificate: [],
  });

  const [country, setCountry] = useState([]);
  const [program, setProgram] = useState([]);
  const [university, setUniversity] = useState([]);


  useEffect(() => {
    fetch("/api/countries")
      .then((res) => res.json())
      .then(
        (res) =>{
          console.log(res);
          
           setCountry(res);
        })
      .catch((error) => console.error(error));


    fetch("/api/programs")
      .then((res) => res.json())
      .then((res) => {
        console.log(res.programs);

        setProgram(res.programs);
      })
      .catch((error) => console.error(error));
   },[]);

  const router = useRouter();


  const handleChange = (
    e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>
  ) => {
    const { name, value } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: value,
    }));

    if (name === "program_id") {

      console.log("Program ID:", formData.program_id);
      

      fetch("/api/universities", {
        method: "POST",
        body: JSON.stringify({programId: formData.program_id}),
      })
        .then((res) => res.json())
        .then((res) => {
          console.log(res);
          setUniversity(res.universities);
        })
        .catch((error) => console.error(error));
    }
  };

const handleFileChange = (e, field) => {
  const files = e.target.files;
  setFormData((prev) => ({
    ...prev,
    [field]: field === "other_certificate" ? Array.from(files) : files[0],
  }));
};

  const nextStep = () => setStep((prevStep) => prevStep + 1);
  const prevStep = () => setStep((prevStep) => prevStep - 1);


  const submitHandler = async (e) => {
    e.preventDefault();
    const formDataToSend = new FormData();

    Object.entries(formData).forEach(([key, value]) => {
      if (key === "other_certificate" && Array.isArray(value)) {
        value.forEach((file, index) => {
          formDataToSend.append(`other_certificate[${index}]`, file);
        });
      } else if (value) {
        formDataToSend.append(key, value);
      }
    });

    console.log("Form Data Entries:");
    for (let pair of formDataToSend.entries()) {
      console.log(pair[0], pair[1]);
    }
    

    try {
      const response = await fetch("/api/register", {
        method: "POST",
        body: formDataToSend,
      });

      const data = await response.json();
      console.log(data);
      
      if (data.message == "success"){
         alert("Registered Successfully! Check your email for OTP");

          localStorage.setItem("email", formData.email);

          router.push("/verify");

      }else{
        alert("Error in registering");
      }

    } catch (error) {
      console.error("Error uploading files:", error);
    }
  };


  return (
    <Container className="d-flex justify-content-center align-items-center">
      <Row className="w-100 justify-content-center">
        <Col md={7}>
          <h2 className="text-center mb-4">Register</h2>
          <Form onSubmit={submitHandler}>
            {step === 1 && (
              <>
                <Form.Group className="mb-3" controlId="formName">
                  <Form.Label>Name</Form.Label>
                  <Form.Control
                    name="name"
                    value={formData.name}
                    onChange={handleChange}
                    type="text"
                    placeholder="Enter your name"
                  />
                </Form.Group>

                <Form.Group className="mb-3" controlId="formEmail">
                  <Form.Label>Email</Form.Label>
                  <Form.Control
                    name="email"
                    value={formData.email}
                    onChange={handleChange}
                    type="email"
                    placeholder="Enter your email"
                  />
                </Form.Group>

                <Form.Group className="mb-3" controlId="formphone_number">
                  <Form.Label>Phone Number</Form.Label>
                  <Form.Control
                    name="phone_number"
                    value={formData.phone_number}
                    onChange={handleChange}
                    type="text"
                    placeholder="Enter your phone number"
                  />
                </Form.Group>
                <Form.Group className="mb-3" controlId="formphone_number">
                  <Form.Label>Id proof</Form.Label>
                  <Form.Control
                    name="id_proof"
                    value={formData.id_proof}
                    onChange={handleChange}
                    type="text"
                    placeholder="Enter your id proof"
                  />
                </Form.Group>
                <Form.Group className="mb-3" controlId="formphone_number">
                  <Form.Label>Password</Form.Label>
                  <Form.Control
                    name="password"
                    value={formData.password}
                    onChange={handleChange}
                    type="text"
                    placeholder="Enter your password"
                  />
                </Form.Group>
                <Form.Group className="mb-3" controlId="formphone_number">
                  <Form.Label>Confirm Password</Form.Label>
                  <Form.Control
                    name="confirmPassword"
                    value={formData.confirmPassword}
                    onChange={handleChange}
                    type="text"
                    placeholder="Enter your confirm password"
                  />
                </Form.Group>

                <Button variant="primary" onClick={nextStep} className="w-100">
                  Next
                </Button>
              </>
            )}

            {step === 2 && (
              <>
                <Form.Group className="mb-3" controlId="formCountry">
                  <Form.Label>Country</Form.Label>
                  <Form.Select
                    name="country_id"
                    value={formData.country_id}
                    onChange={handleChange}
                  >
                    <option value="">Select a Country</option>
                    {country
                      ? country.map((country) => (
                          <option key={country.id} value={country.id}>
                            {country.name}
                          </option>
                        ))
                      : null}
                  </Form.Select>
                </Form.Group>
                <Form.Group className="mb-3" controlId="formProgram">
                  <Form.Label>Select Program</Form.Label>
                  <Form.Select
                    name="program_id"
                    value={formData.program_id}
                    onChange={handleChange}
                  >
                    <option value="">Select a program</option>
                    {program
                      ? program.map((program) => (
                          <option key={program.id} value={program.id}>
                            {program.name}
                          </option>
                        ))
                      : null}
                  </Form.Select>
                </Form.Group>

                <Form.Group className="mb-3" controlId="formUniversity">
                  <Form.Label>Select University</Form.Label>
                  <Form.Select
                    name="university_id"
                    value={formData.university_id}
                    onChange={handleChange}
                  >
                    <option value="">Select a university</option>
                    {university
                      ? university.map((university) => (
                          <option key={university.id} value={university.id}>
                            {university.name}
                          </option>
                        ))
                      : null}
                  </Form.Select>
                </Form.Group>

                <Button variant="secondary" onClick={prevStep} className="me-2">
                  Back
                </Button>
                <Button variant="primary" onClick={nextStep}>
                  Next
                </Button>
              </>
            )}

            {step === 3 && (
              <>
                <Form.Group className="mb-3" controlId="formtenth_certificate">
                  <Form.Label>10th Certificate</Form.Label>
                  <Form.Control
                    type="file"
                    onChange={(e) => handleFileChange(e, "tenth_certificate")}
                  />
                </Form.Group>

                <Form.Group
                  className="mb-3"
                  controlId="formtwelfth_certificate"
                >
                  <Form.Label>12th Certificate</Form.Label>
                  <Form.Control
                    type="file"
                    onChange={(e) => handleFileChange(e, "twelfth_certificate")}
                  />
                </Form.Group>

                <Form.Group className="mb-3" controlId="formother_certificate">
                  <Form.Label>Other Certificates</Form.Label>
                  <Form.Control
                    type="file"
                    multiple
                    onChange={(e) => handleFileChange(e, "other_certificate")}
                  />
                </Form.Group>

                <Button variant="secondary" onClick={prevStep} className="me-2">
                  Back
                </Button>
                <Button variant="success" type="submit">
                  Submit
                </Button>
              </>
            )}
          </Form>
        </Col>
      </Row>
    </Container>
  );
}
